{
  "title": "Introduction to Python for Game Development",
  "description": "This course is designed for beginners who want to learn Python with a focus on game development. Participants will gain foundational programming skills and practical experience in creating simple games using Python.",
  "modules": [
    {
      "id": "module1",
      "title": "Getting Started with Python",
      "description": "Introduction to Python programming, including installation, basic syntax, data types, and control structures. Learners will set up their development environment and write their first simple Python programs."
    },
    {
      "id": "module2",
      "title": "Understanding Game Development Concepts",
      "description": "Explore the fundamentals of game development, including game loops, event handling, and graphics. This module will introduce libraries such as Pygame and how they are used to create interactive games."
    },
    {
      "id": "module3",
      "title": "Building Your First Game",
      "description": "Hands-on project where learners will apply their knowledge to create a simple 2D game using Python and Pygame. This module will cover game design principles and how to implement game mechanics."
    },
    {
      "id": "module4",
      "title": "Enhancing Your Game and Next Steps",
      "description": "Learn how to add features to your game, such as scoring systems, levels, and sound effects. This module will also discuss resources for further learning and how to continue developing your skills in Python and game development."
    }
  ]
}
